// Normalização simplificada para MAVO.AI
const payload = $json;

// Extrair dados básicos
const ticketId = payload.ticket_id || payload.ticket?.id || `MAVO-${Date.now()}`;
const cliente = payload.cliente || payload.customer?.name || payload.contact?.name || 'Cliente não identificado';
const telefone = payload.cliente_telefone || payload.phone || payload.contact?.phoneNumber || '';

// Extrair mensagem
let mensagem = '';
if (typeof payload.mensagem === 'string') {
  mensagem = payload.mensagem;
} else if (Array.isArray(payload.mensagens)) {
  mensagem = payload.mensagens.join(' ');
} else if (typeof payload.mensagens === 'string') {
  mensagem = payload.mensagens;
} else if (payload.message?.text) {
  mensagem = payload.message.text;
}

// Validar dados mínimos
if (!mensagem.trim()) {
  throw new Error('Mensagem não pode ser vazia');
}

if (!telefone) {
  console.warn('Telefone do cliente não fornecido');
}

// Formatar para API MAVO.AI
const output = {
  ticket_id: ticketId,
  cliente: cliente,
  mensagens: mensagem.trim(),
  canal: payload.canal || 'whatsapp',
  tecnico: payload.tecnico || 'n8n',
  data_evento: payload.data_evento || new Date().toISOString(),
  cliente_telefone: telefone,
  // Campos adicionais para triagem
  origem: 'n8n',
  timestamp: new Date().toISOString()
};

return [{ json: output }];

// Log de sucesso
const response = $json;

console.log('✅ Ingestão bem-sucedida:', {
  ticket_id: response.ticket_id,
  atendimento_id: response.atendimento_id,
  timestamp: new Date().toISOString()
});

return [{ json: { status: 'success', message: 'Atendimento ingerido com sucesso', data: response } }];

// Log de erro
const error = $json;

console.error('❌ Erro na ingestão:', {
  error: error.message || error.error,
  timestamp: new Date().toISOString(),
  payload: $input.first().json
});

return [{ json: { status: 'error', message: error.message || 'Erro na ingestão', original: $input.first().json } }];
